"""Model selection: train_test_split, cross_val_score."""
import numpy as np


def train_test_split(*arrays, test_size=0.25, train_size=None, random_state=None,
                     shuffle=True, stratify=None):
    n = len(arrays[0])
    rng = np.random.RandomState(random_state)
    indices = np.arange(n)
    if shuffle:
        rng.shuffle(indices)
    if isinstance(test_size, float):
        split = int(n * (1 - test_size))
    else:
        split = n - test_size
    train_idx, test_idx = indices[:split], indices[split:]
    result = []
    for arr in arrays:
        arr = np.asarray(arr)
        result.append(arr[train_idx])
        result.append(arr[test_idx])
    return result


def cross_val_score(estimator, X, y=None, *, groups=None, scoring=None, cv=5,
                    n_jobs=None, verbose=0, fit_params=None,
                    params=None, pre_dispatch='2*n_jobs',
                    error_score=np.nan):
    X, y = np.asarray(X), np.asarray(y)
    n = len(X)
    fold_size = n // cv
    scores = []
    indices = np.arange(n)
    for i in range(cv):
        test_idx = indices[i * fold_size:(i + 1) * fold_size] if i < cv - 1 else indices[i * fold_size:]
        train_idx = np.setdiff1d(indices, test_idx)
        from sklearn.base import clone
        est = clone(estimator)
        est.fit(X[train_idx], y[train_idx])
        scores.append(est.score(X[test_idx], y[test_idx]))
    return np.array(scores)


class StratifiedKFold:
    def __init__(self, n_splits=5, shuffle=False, random_state=None):
        self.n_splits = n_splits
        self.shuffle = shuffle
        self.random_state = random_state

    def split(self, X, y, groups=None):
        X, y = np.asarray(X), np.asarray(y)
        n = len(y)
        rng = np.random.RandomState(self.random_state)
        classes = np.unique(y)
        # Group indices by class
        class_indices = {}
        for c in classes:
            idx = np.where(y == c)[0]
            if self.shuffle:
                rng.shuffle(idx)
            class_indices[c] = idx
        # Distribute into folds
        folds = [[] for _ in range(self.n_splits)]
        for c in classes:
            idx = class_indices[c]
            fold_sizes = np.full(self.n_splits, len(idx) // self.n_splits, dtype=int)
            fold_sizes[:len(idx) % self.n_splits] += 1
            pos = 0
            for fold_idx, size in enumerate(fold_sizes):
                folds[fold_idx].extend(idx[pos:pos + size].tolist())
                pos += size
        for fold_idx in range(self.n_splits):
            test_idx = np.array(folds[fold_idx], dtype=int)
            train_idx = np.array([i for i in range(n) if i not in set(folds[fold_idx])], dtype=int)
            yield train_idx, test_idx

    def get_n_splits(self, X=None, y=None):
        return self.n_splits


class GridSearchCV:
    def __init__(self, estimator, param_grid, *, scoring=None, n_jobs=None,
                 refit=True, cv=5, verbose=0, pre_dispatch='2*n_jobs',
                 error_score=np.nan, return_train_score=False):
        self.estimator = estimator
        self.param_grid = param_grid
        self.scoring = scoring
        self.n_jobs = n_jobs
        self.refit = refit
        self.cv = cv
        self.verbose = verbose
        self.pre_dispatch = pre_dispatch
        self.error_score = error_score
        self.return_train_score = return_train_score
        self.best_params_ = None
        self.best_score_ = None
        self.best_estimator_ = None
        self.cv_results_ = None

    def _param_combinations(self):
        keys = list(self.param_grid.keys())
        if not keys:
            return [{}]
        values = [self.param_grid[k] for k in keys]
        combos = [{}]
        for key, vals in zip(keys, values):
            new_combos = []
            for combo in combos:
                for v in vals:
                    c = dict(combo)
                    c[key] = v
                    new_combos.append(c)
            combos = new_combos
        return combos

    def fit(self, X, y):
        X, y = np.asarray(X), np.asarray(y)
        combos = self._param_combinations()
        best_score = -np.inf
        results = {'params': [], 'mean_test_score': []}
        for params in combos:
            scores = cross_val_score(
                type(self.estimator)(**{**self.estimator.get_params(), **params}),
                X, y, cv=self.cv
            )
            mean_score = np.mean(scores)
            results['params'].append(params)
            results['mean_test_score'].append(mean_score)
            if mean_score > best_score:
                best_score = mean_score
                self.best_params_ = params
                self.best_score_ = mean_score
        self.cv_results_ = results
        # Refit on full data with best params
        self.best_estimator_ = type(self.estimator)(
            **{**self.estimator.get_params(), **self.best_params_}
        )
        self.best_estimator_.fit(X, y)
        return self

    def predict(self, X):
        return self.best_estimator_.predict(X)

    def score(self, X, y):
        return self.best_estimator_.score(X, y)

    def get_params(self, deep=True):
        return {
            'estimator': self.estimator,
            'param_grid': self.param_grid,
            'cv': self.cv,
            'scoring': self.scoring
        }


# ---------------------------------------------------------------------------
# Additional cross-validation splitters and utilities
# ---------------------------------------------------------------------------

class KFold:
    """K-Fold cross-validator."""

    def __init__(self, n_splits=5, shuffle=False, random_state=None):
        self.n_splits = n_splits
        self.shuffle = shuffle
        self.random_state = random_state

    def split(self, X, y=None, groups=None):
        X = np.asarray(X)
        n = len(X)
        indices = np.arange(n)
        if self.shuffle:
            rng = np.random.RandomState(self.random_state)
            rng.shuffle(indices)
        fold_sizes = np.full(self.n_splits, n // self.n_splits, dtype=int)
        fold_sizes[:n % self.n_splits] += 1
        current = 0
        for fold_size in fold_sizes:
            test_idx = indices[current:current + fold_size]
            train_idx = np.concatenate([indices[:current],
                                        indices[current + fold_size:]])
            yield train_idx, test_idx
            current += fold_size

    def get_n_splits(self, X=None, y=None, groups=None):
        return self.n_splits


class LeaveOneOut:
    """Leave-One-Out cross-validator."""

    def split(self, X, y=None, groups=None):
        X = np.asarray(X)
        n = len(X)
        indices = np.arange(n)
        for i in range(n):
            test_idx = np.array([i])
            train_idx = np.concatenate([indices[:i], indices[i + 1:]])
            yield train_idx, test_idx

    def get_n_splits(self, X=None, y=None, groups=None):
        if X is not None:
            return len(np.asarray(X))
        raise ValueError("X is required to determine n_splits for LeaveOneOut")


class RepeatedKFold:
    """Repeated K-Fold cross-validator."""

    def __init__(self, n_splits=5, n_repeats=10, random_state=None):
        self.n_splits = n_splits
        self.n_repeats = n_repeats
        self.random_state = random_state

    def split(self, X, y=None, groups=None):
        rng = np.random.RandomState(self.random_state)
        for rep in range(self.n_repeats):
            cv = KFold(n_splits=self.n_splits, shuffle=True,
                       random_state=rng.randint(0, 2**31))
            for train_idx, test_idx in cv.split(X, y, groups):
                yield train_idx, test_idx

    def get_n_splits(self, X=None, y=None, groups=None):
        return self.n_splits * self.n_repeats


class RepeatedStratifiedKFold:
    """Repeated Stratified K-Fold cross-validator."""

    def __init__(self, n_splits=5, n_repeats=10, random_state=None):
        self.n_splits = n_splits
        self.n_repeats = n_repeats
        self.random_state = random_state

    def split(self, X, y, groups=None):
        rng = np.random.RandomState(self.random_state)
        for rep in range(self.n_repeats):
            cv = StratifiedKFold(n_splits=self.n_splits, shuffle=True,
                                 random_state=rng.randint(0, 2**31))
            for train_idx, test_idx in cv.split(X, y):
                yield train_idx, test_idx

    def get_n_splits(self, X=None, y=None, groups=None):
        return self.n_splits * self.n_repeats


class ShuffleSplit:
    """Random permutation cross-validator."""

    def __init__(self, n_splits=10, test_size=None, train_size=None,
                 random_state=None):
        self.n_splits = n_splits
        self.test_size = test_size
        self.train_size = train_size
        self.random_state = random_state

    def split(self, X, y=None, groups=None):
        X = np.asarray(X)
        n = len(X)
        rng = np.random.RandomState(self.random_state)
        test_size = self.test_size
        if test_size is None:
            test_size = 0.1
        if isinstance(test_size, float):
            n_test = int(np.ceil(test_size * n))
        else:
            n_test = test_size
        if self.train_size is not None:
            if isinstance(self.train_size, float):
                n_train = int(np.floor(self.train_size * n))
            else:
                n_train = self.train_size
        else:
            n_train = n - n_test
        for _ in range(self.n_splits):
            perm = rng.permutation(n)
            yield perm[:n_train], perm[n_train:n_train + n_test]

    def get_n_splits(self, X=None, y=None, groups=None):
        return self.n_splits


class StratifiedShuffleSplit:
    """Stratified ShuffleSplit cross-validator."""

    def __init__(self, n_splits=10, test_size=None, train_size=None,
                 random_state=None):
        self.n_splits = n_splits
        self.test_size = test_size
        self.train_size = train_size
        self.random_state = random_state

    def split(self, X, y, groups=None):
        X = np.asarray(X)
        y = np.asarray(y)
        n = len(y)
        rng = np.random.RandomState(self.random_state)
        test_size = self.test_size if self.test_size is not None else 0.1
        if isinstance(test_size, float):
            n_test = int(np.ceil(test_size * n))
        else:
            n_test = test_size
        if self.train_size is not None:
            if isinstance(self.train_size, float):
                n_train = int(np.floor(self.train_size * n))
            else:
                n_train = self.train_size
        else:
            n_train = n - n_test
        classes = np.unique(y)
        for _ in range(self.n_splits):
            train_indices = []
            test_indices = []
            for c in classes:
                c_idx = np.where(y == c)[0]
                rng.shuffle(c_idx)
                c_n_test = max(1, int(np.round(n_test * len(c_idx) / n)))
                c_n_train = max(1, int(np.round(n_train * len(c_idx) / n)))
                test_indices.extend(c_idx[:c_n_test].tolist())
                train_indices.extend(c_idx[c_n_test:c_n_test + c_n_train].tolist())
            yield np.array(train_indices, dtype=int), np.array(test_indices, dtype=int)

    def get_n_splits(self, X=None, y=None, groups=None):
        return self.n_splits


class GroupKFold:
    """K-fold cross-validator with non-overlapping groups."""

    def __init__(self, n_splits=5):
        self.n_splits = n_splits

    def split(self, X, y=None, groups=None):
        X = np.asarray(X)
        groups = np.asarray(groups)
        unique_groups = np.unique(groups)
        n_groups = len(unique_groups)
        if n_groups < self.n_splits:
            raise ValueError(
                f"Cannot have n_splits={self.n_splits} > n_groups={n_groups}")
        # Assign groups to folds
        fold_assignment = {}
        for i, g in enumerate(unique_groups):
            fold_assignment[g] = i % self.n_splits
        for fold in range(self.n_splits):
            test_mask = np.array([fold_assignment[g] == fold for g in groups])
            test_idx = np.where(test_mask)[0]
            train_idx = np.where(~test_mask)[0]
            yield train_idx, test_idx

    def get_n_splits(self, X=None, y=None, groups=None):
        return self.n_splits


class GroupShuffleSplit:
    """Shuffle-Group(s)-Out cross-validator."""

    def __init__(self, n_splits=5, test_size=None, train_size=None,
                 random_state=None):
        self.n_splits = n_splits
        self.test_size = test_size
        self.train_size = train_size
        self.random_state = random_state

    def split(self, X, y=None, groups=None):
        X = np.asarray(X)
        groups = np.asarray(groups)
        unique_groups = np.unique(groups)
        n_groups = len(unique_groups)
        rng = np.random.RandomState(self.random_state)
        test_size = self.test_size if self.test_size is not None else 0.2
        if isinstance(test_size, float):
            n_test_groups = max(1, int(np.ceil(test_size * n_groups)))
        else:
            n_test_groups = test_size
        for _ in range(self.n_splits):
            perm = rng.permutation(n_groups)
            test_groups = set(unique_groups[perm[:n_test_groups]])
            test_mask = np.array([g in test_groups for g in groups])
            test_idx = np.where(test_mask)[0]
            train_idx = np.where(~test_mask)[0]
            yield train_idx, test_idx

    def get_n_splits(self, X=None, y=None, groups=None):
        return self.n_splits


class TimeSeriesSplit:
    """Time Series cross-validator with forward chaining."""

    def __init__(self, n_splits=5, max_train_size=None, test_size=None, gap=0):
        self.n_splits = n_splits
        self.max_train_size = max_train_size
        self.test_size = test_size
        self.gap = gap

    def split(self, X, y=None, groups=None):
        X = np.asarray(X)
        n = len(X)
        indices = np.arange(n)
        if self.test_size is not None:
            test_size = self.test_size
        else:
            test_size = n // (self.n_splits + 1)
        test_starts = range(n - self.n_splits * test_size, n, test_size)
        for test_start in test_starts:
            train_end = test_start - self.gap
            if train_end <= 0:
                continue
            if self.max_train_size is not None:
                train_start = max(0, train_end - self.max_train_size)
            else:
                train_start = 0
            train_idx = indices[train_start:train_end]
            test_idx = indices[test_start:test_start + test_size]
            if len(train_idx) > 0 and len(test_idx) > 0:
                yield train_idx, test_idx

    def get_n_splits(self, X=None, y=None, groups=None):
        return self.n_splits


class ParameterGrid:
    """Grid of parameters with a discrete number of values for each."""

    def __init__(self, param_grid):
        if isinstance(param_grid, dict):
            self.param_grid = [param_grid]
        else:
            self.param_grid = list(param_grid)

    def __iter__(self):
        for grid in self.param_grid:
            keys = list(grid.keys())
            if not keys:
                yield {}
                continue
            values = [grid[k] for k in keys]
            combos = [{}]
            for key, vals in zip(keys, values):
                new_combos = []
                for combo in combos:
                    for v in vals:
                        c = dict(combo)
                        c[key] = v
                        new_combos.append(c)
                combos = new_combos
            for combo in combos:
                yield combo

    def __len__(self):
        total = 0
        for grid in self.param_grid:
            n = 1
            for v in grid.values():
                n *= len(v)
            total += n
        return total

    def __getitem__(self, idx):
        for i, params in enumerate(self):
            if i == idx:
                return params
        raise IndexError(f"ParameterGrid index {idx} out of range")


class ParameterSampler:
    """Random samples from parameter distributions."""

    def __init__(self, param_distributions, n_iter, *, random_state=None):
        self.param_distributions = param_distributions
        self.n_iter = n_iter
        self.random_state = random_state

    def __iter__(self):
        rng = np.random.RandomState(self.random_state)
        for _ in range(self.n_iter):
            params = {}
            for key, dist in self.param_distributions.items():
                if hasattr(dist, 'rvs'):
                    params[key] = dist.rvs(random_state=rng)
                elif isinstance(dist, (list, tuple, np.ndarray)):
                    params[key] = dist[rng.randint(len(dist))]
                else:
                    params[key] = dist
            yield params

    def __len__(self):
        return self.n_iter


class RandomizedSearchCV:
    """Randomized search on hyper-parameters."""

    def __init__(self, estimator, param_distributions, *, n_iter=10,
                 scoring=None, n_jobs=None, refit=True, cv=None, verbose=0,
                 pre_dispatch='2*n_jobs', random_state=None,
                 error_score=np.nan, return_train_score=False):
        self.estimator = estimator
        self.param_distributions = param_distributions
        self.n_iter = n_iter
        self.scoring = scoring
        self.n_jobs = n_jobs
        self.refit = refit
        self.cv = cv if cv is not None else 5
        self.verbose = verbose
        self.pre_dispatch = pre_dispatch
        self.random_state = random_state
        self.error_score = error_score
        self.return_train_score = return_train_score
        self.best_params_ = None
        self.best_score_ = None
        self.best_estimator_ = None
        self.cv_results_ = None

    def fit(self, X, y=None):
        X = np.asarray(X)
        if y is not None:
            y = np.asarray(y)
        sampler = ParameterSampler(self.param_distributions, self.n_iter,
                                   random_state=self.random_state)
        best_score = -np.inf
        results = {'params': [], 'mean_test_score': []}
        from sklearn.base import clone as _clone
        for params in sampler:
            est = _clone(self.estimator)
            for k, v in params.items():
                setattr(est, k, v)
            scores = cross_val_score(est, X, y, cv=self.cv)
            mean_score = np.mean(scores)
            results['params'].append(params)
            results['mean_test_score'].append(mean_score)
            if mean_score > best_score:
                best_score = mean_score
                self.best_params_ = dict(params)
                self.best_score_ = mean_score
        self.cv_results_ = results
        if self.refit:
            self.best_estimator_ = _clone(self.estimator)
            for k, v in self.best_params_.items():
                setattr(self.best_estimator_, k, v)
            self.best_estimator_.fit(X, y)
        return self

    def predict(self, X):
        return self.best_estimator_.predict(np.asarray(X))

    def score(self, X, y):
        return self.best_estimator_.score(np.asarray(X), np.asarray(y))

    def get_params(self, deep=True):
        return {
            'estimator': self.estimator,
            'param_distributions': self.param_distributions,
            'n_iter': self.n_iter,
            'cv': self.cv,
            'scoring': self.scoring
        }


def _resolve_cv(cv, y=None):
    """Resolve cv parameter to a splitter object."""
    if cv is None:
        cv = 5
    if isinstance(cv, int):
        if y is not None:
            return StratifiedKFold(n_splits=cv)
        return KFold(n_splits=cv)
    return cv


def cross_validate(estimator, X, y=None, *, groups=None, scoring=None, cv=None,
                   n_jobs=None, verbose=0, fit_params=None,
                   pre_dispatch='2*n_jobs', return_train_score=False,
                   return_estimator=False, return_indices=False,
                   error_score=np.nan):
    """Evaluate metric(s) by cross-validation, returning a dict of arrays."""
    import time as _time
    X = np.asarray(X)
    if y is not None:
        y = np.asarray(y)
    from sklearn.base import clone as _clone
    cv_splitter = _resolve_cv(cv, y)
    test_scores = []
    train_scores = []
    fit_times = []
    score_times = []
    estimators = []
    indices = {'train': [], 'test': []}

    for train_idx, test_idx in cv_splitter.split(X, y, groups):
        est = _clone(estimator)
        t0 = _time.time()
        if fit_params:
            est.fit(X[train_idx], y[train_idx] if y is not None else None,
                    **fit_params)
        else:
            est.fit(X[train_idx], y[train_idx] if y is not None else None)
        fit_time = _time.time() - t0

        t0 = _time.time()
        test_scores.append(est.score(X[test_idx],
                                     y[test_idx] if y is not None else None))
        score_time = _time.time() - t0

        fit_times.append(fit_time)
        score_times.append(score_time)

        if return_train_score:
            train_scores.append(est.score(
                X[train_idx], y[train_idx] if y is not None else None))
        if return_estimator:
            estimators.append(est)
        if return_indices:
            indices['train'].append(train_idx)
            indices['test'].append(test_idx)

    result = {
        'test_score': np.array(test_scores),
        'fit_time': np.array(fit_times),
        'score_time': np.array(score_times),
    }
    if return_train_score:
        result['train_score'] = np.array(train_scores)
    if return_estimator:
        result['estimator'] = estimators
    if return_indices:
        result['indices'] = indices
    return result


def learning_curve(estimator, X, y, *, groups=None,
                   train_sizes=None, cv=None, scoring=None,
                   exploit_incremental_learning=False, n_jobs=None,
                   pre_dispatch='all', verbose=0, shuffle=False,
                   random_state=None, error_score=np.nan,
                   return_times=False):
    """Determine training sizes, train scores, and test scores."""
    if train_sizes is None:
        train_sizes = np.linspace(0.1, 1.0, 5)
    X = np.asarray(X)
    y = np.asarray(y)
    from sklearn.base import clone as _clone
    cv_splitter = _resolve_cv(cv, y)

    # Collect all splits first
    splits = list(cv_splitter.split(X, y, groups))

    train_sizes_input = np.asarray(train_sizes)
    all_train_scores = []
    all_test_scores = []
    abs_train_sizes = []

    for size in train_sizes_input:
        fold_train_scores = []
        fold_test_scores = []
        for train_idx, test_idx in splits:
            if isinstance(size, float) or (isinstance(size, np.floating)):
                n_train = max(1, int(size * len(train_idx)))
            else:
                n_train = int(size)
            if shuffle:
                rng = np.random.RandomState(random_state)
                rng.shuffle(train_idx)
            sub_train_idx = train_idx[:n_train]
            est = _clone(estimator)
            est.fit(X[sub_train_idx], y[sub_train_idx])
            fold_train_scores.append(est.score(X[sub_train_idx], y[sub_train_idx]))
            fold_test_scores.append(est.score(X[test_idx], y[test_idx]))
        all_train_scores.append(fold_train_scores)
        all_test_scores.append(fold_test_scores)
        # Use last fold's n_train as representative size
        if isinstance(size, float) or (isinstance(size, np.floating)):
            abs_train_sizes.append(max(1, int(size * len(splits[0][0]))))
        else:
            abs_train_sizes.append(int(size))

    result = (np.array(abs_train_sizes),
              np.array(all_train_scores),
              np.array(all_test_scores))
    return result


def validation_curve(estimator, X, y, *, param_name, param_range,
                     groups=None, cv=None, scoring=None, n_jobs=None,
                     pre_dispatch='all', verbose=0, error_score=np.nan):
    """Validation curve: train/test scores for varying parameter values."""
    X = np.asarray(X)
    y = np.asarray(y)
    from sklearn.base import clone as _clone
    cv_splitter = _resolve_cv(cv, y)
    splits = list(cv_splitter.split(X, y, groups))

    all_train_scores = []
    all_test_scores = []

    for val in param_range:
        fold_train_scores = []
        fold_test_scores = []
        for train_idx, test_idx in splits:
            est = _clone(estimator)
            setattr(est, param_name, val)
            est.fit(X[train_idx], y[train_idx])
            fold_train_scores.append(est.score(X[train_idx], y[train_idx]))
            fold_test_scores.append(est.score(X[test_idx], y[test_idx]))
        all_train_scores.append(fold_train_scores)
        all_test_scores.append(fold_test_scores)

    return np.array(all_train_scores), np.array(all_test_scores)